export default function HowItWorksStepsSection({
  data,
  style,
  isBuilder = false,
}: HowItWorksStepsSectionProps) {
  const {
    eyebrow = 'Platform in action',
    title = 'From blank canvas to running system — here\'s what your team actually does',
    steps = DEFAULT_STEPS,
    accentColor = '#4F7FFF',
    accentColor2 = '#7B5CFF',
  } = data;

  const sectionRef = useRef<HTMLDivElement>(null);

  /* Scroll-reveal */
  useEffect(() => {
    if (isBuilder) {
      sectionRef.current?.querySelectorAll<HTMLElement>('.hiw-row').forEach(el => {
        el.style.opacity = '1';
        el.style.transform = 'none';
      });
      return;
    }
    const rows = sectionRef.current?.querySelectorAll<HTMLElement>('.hiw-row');
    if (!rows) return;
    const observer = new IntersectionObserver(
      entries => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            (entry.target as HTMLElement).style.opacity = '1';
            (entry.target as HTMLElement).style.transform = 'translateY(0)';
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.12 }
    );
    rows.forEach(el => observer.observe(el));
    return () => observer.disconnect();
  }, [isBuilder, steps]);

  return (
    <section className="pb-[110px] bg-[#07080A] dark:bg-[#07080A] light:bg-white">
      <div className="max-w-[1180px] mx-auto px-5 md:px-10">

        {/* Header */}
        <div className="text-center mb-20">
          <div
            className="inline-flex items-center gap-2 rounded-full px-4 py-1.5 mb-6 border"
            style={{ background: `rgba(79,127,255,0.08)`, borderColor: `rgba(79,127,255,0.20)` }}
          >
            <span className="w-1.5 h-1.5 rounded-full animate-pulse" style={{ background: accentColor }} />
            <span className="text-[11px] font-semibold tracking-[0.16em] uppercase" style={{ color: accentColor }}>
              {eyebrow}
            </span>
          </div>
          <h2
            className="font-extrabold leading-[1.15] tracking-tight text-[#F0F2F8] dark:text-[#F0F2F8] light:text-slate-900 max-w-[700px] mx-auto"
            style={{ fontSize: 'clamp(28px, 4vw, 44px)' }}
          >
            {title}
          </h2>
        </div>

        {/* Steps */}
        <div ref={sectionRef} className="flex flex-col gap-[100px]">
          {steps.map((step, idx) => (
            <div
              key={idx}
              className={`hiw-row grid grid-cols-1 md:grid-cols-2 gap-[72px] items-center transition-all duration-700`}
              style={{
                opacity: isBuilder ? 1 : 0,
                transform: isBuilder ? 'none' : 'translateY(28px)',
                direction: step.flip ? 'rtl' : 'ltr',
              }}
            >
              {/* Text */}
              <div style={{ direction: 'ltr' }}>
                <div
                  className="text-[11px] font-bold tracking-[0.16em] uppercase mb-3.5"
                  style={{ color: accentColor }}
                >
                  {step.stepNumber}
                </div>
                <h3 className="font-bold text-[28px] leading-[1.25] tracking-tight text-[#F0F2F8] dark:text-[#F0F2F8] light:text-slate-900 mb-4">
                  {step.title}
                </h3>
                <p className="text-[15px] font-light text-[#8A8FA8] leading-[1.75] mb-6">
                  {step.body}
                </p>
                <div className="flex flex-wrap gap-2">
                  {step.chips.map((chip, ci) => (
                    <span
                      key={ci}
                      className="text-[11.5px] text-[#4A4F65] border border-white/[0.07] rounded-[7px] px-3 py-1.5 transition-all duration-200 hover:border-[rgba(79,127,255,0.25)] hover:text-[#8A8FA8]"
                    >
                      {chip}
                    </span>
                  ))}
                </div>
              </div>

              {/* Visual */}
              <div style={{ direction: 'ltr' }}>
                <StepVisual step={step} accentColor={accentColor} />
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
